    WHERE
      identity_visibility."hasNamedProfile" = true
      OR identity_counts."visibleAssetCount" >= $7
  ),
  face_classification AS (
    SELECT
      accessible_detected_faces."assetFaceId",
      bool_or(
        COALESCE(eligible_identities."hasVisibleProfile", false)
